t.script:
odoo.define('petadigi.DashboardMap', function (require) {
  'use strict';

  $(document).ready(function () {
    // check if page contains dashboard_map
    if ($('#dashboard_map').length) {
      // only init if not yet
      if (!window._dashboardMapInit) {
        window._dashboardMapInit = true;
        var map = L.map('dashboard_map').setView([-3.31987, 104.91459], 8); // Koordinat pusat Sumatera Selatan
        L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
          attribution: '© OpenStreetMap'
        }).addTo(map);
      }
    }
  });
});
